// GET básico — pedir una lista de posts
async function obtenerPosts() {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts');
  const posts = await res.json();

  console.log(`Hay ${posts.length} posts`);
  console.log('Primero:', posts[0].title);
}

obtenerPosts();

// GET con manejo de errores correcto
async function obtenerUsuario(id) {
  try {
    const res = await fetch(`https://jsonplaceholder.typicode.com/users/${id}`);

    if (!res.ok) {
      throw new Error(`No encontrado (status: ${res.status})`);
    }

    const usuario = await res.json();
    return usuario;
  } catch (error) {
    console.error('Error:', error.message);
    return null;
  }
}

const usuario = await obtenerUsuario(1);
console.log(usuario?.name); // 'Leanne Graham'

// POST — crear un recurso nuevo
async function crearPost(titulo, cuerpo) {
  const res = await fetch('https://jsonplaceholder.typicode.com/posts', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ title: titulo, body: cuerpo, userId: 1 })
  });

  if (!res.ok) throw new Error(`Error ${res.status}`);

  const postCreado = await res.json();
  console.log('Creado con id:', postCreado.id); // 101
  return postCreado;
}

await crearPost('Mi primer post', 'Contenido del post');

