// Simulación de fetch para el ejercicio
function mockFetch(url) {
  if (url.includes('error')) {
    return Promise.resolve({ ok: false, status: 404, json: () => Promise.resolve({}) });
  }
  return Promise.resolve({
    ok: true,
    status: 200,
    json: () => Promise.resolve({ datos: 'ok', url })
  });
}

async function fetchSeguro(url, _fetch = mockFetch) {
  try {
    const res = await _fetch(url);
    if (!res.ok) throw new Error('HTTP ' + res.status);
    return await res.json();
  } catch (error) {
    return { error: error.message };
  }
}

const exitoso = await fetchSeguro('https://api.ejemplo.com/datos');
const fallido = await fetchSeguro('https://api.ejemplo.com/error');
